SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS status_history;
DROP TABLE IF EXISTS report;
DROP TABLE IF EXISTS category;
DROP TABLE IF EXISTS district;
DROP TABLE IF EXISTS user;
SET FOREIGN_KEY_CHECKS = 1;
CREATE TABLE district (id INT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(100) NOT NULL UNIQUE, code VARCHAR(20) NOT NULL UNIQUE, description VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE user (id INT PRIMARY KEY AUTO_INCREMENT, username VARCHAR(50) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, email VARCHAR(100) NOT NULL UNIQUE, full_name VARCHAR(100) NOT NULL, role ENUM('RESIDENT', 'ADMIN') NOT NULL DEFAULT 'RESIDENT', district_id INT, is_active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (district_id) REFERENCES district(id) ON DELETE SET NULL, INDEX idx_username (username), INDEX idx_email (email), INDEX idx_role (role)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE category (id INT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(100) NOT NULL UNIQUE, description VARCHAR(255), icon VARCHAR(50), is_active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE report (id INT PRIMARY KEY AUTO_INCREMENT, user_id INT NOT NULL, category_id INT NOT NULL, title VARCHAR(200) NOT NULL, description TEXT NOT NULL, location VARCHAR(255) NOT NULL, latitude DECIMAL(10, 8), longitude DECIMAL(11, 8), image_path VARCHAR(255), status ENUM('PENDING', 'IN_REVIEW', 'IN_PROGRESS', 'RESOLVED') NOT NULL DEFAULT 'PENDING', priority ENUM('LOW', 'MEDIUM', 'HIGH', 'CRITICAL') DEFAULT 'MEDIUM', assigned_to INT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, resolved_at TIMESTAMP NULL, FOREIGN KEY (user_id) REFERENCES user(id) ON DELETE CASCADE, FOREIGN KEY (category_id) REFERENCES category(id) ON DELETE RESTRICT, FOREIGN KEY (assigned_to) REFERENCES user(id) ON DELETE SET NULL, INDEX idx_user_id (user_id), INDEX idx_status (status), INDEX idx_category_id (category_id), INDEX idx_assigned_to (assigned_to), FULLTEXT idx_description (title, description)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE status_history (id INT PRIMARY KEY AUTO_INCREMENT, report_id INT NOT NULL, old_status VARCHAR(20), new_status VARCHAR(20) NOT NULL, changed_by INT NOT NULL, comment TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (report_id) REFERENCES report(id) ON DELETE CASCADE, FOREIGN KEY (changed_by) REFERENCES user(id) ON DELETE RESTRICT, INDEX idx_report_id (report_id), INDEX idx_created_at (created_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
